package a.b;import okhttp3.*;import org.apache.commons.lang3.StringUtils;import org.json.JSONObject;import java.io.File;import java.io.FileOutputStream;import java.io.IOException;import java.net.*;import java.util.*;/** * 一些关于 网络请求 的相关方法 * @author qscbm187531 */public class NetUtil &#123;    static OkHttpClient client = new OkHttpClient();    /**     * 发送普通POST请求     *     * @param url 链接地址     */    public static String sendPostJsonRequest(String url) throws IOException &#123;        return sendPostJsonRequest(url, new HashMap&lt;&gt;(), &quot;&quot;);    &#125;    /**     * 发送普通POST请求（带Header）     *     * @param url 链接地址     */    public static String sendPostJsonRequest(String url, HashMap&lt;String, String&gt; Header) throws IOException &#123;        return sendPostJsonRequest(url, Header, &quot;&quot;);    &#125;    /**     * 发送普通POST请求（带参数）     *     * @param url 链接地址     */    public static String sendPostJsonRequest(String url, String param) throws IOException &#123;        return sendPostJsonRequest(url, null, param);    &#125;    /**     * 发送普通POST请求（带Header和参数）     *     * @param url 链接地址     * @param Header Header     * @param param 参数     */    public static String sendPostJsonRequest(String url, HashMap&lt;String, String&gt; Header, String param) throws IOException &#123;        Request.Builder builder = new Request.Builder();        builder.url(url).post(RequestBody.create(MediaType.parse(&quot;application/json&quot;), param));        JSONObject json = new JSONObject(Header);        for (int i = 0; i &lt; json.keySet().size(); i++) &#123;            builder.addHeader(Header.keySet().stream().toList().get(i), Header.values().stream().toList().get(i));        &#125;        Response response = client.newCall(builder.build()).execute();        String a = Objects.requireNonNull(response.body()).string();        response.close();        return a;    &#125;    /**     * 发送普通的Get请求（带Header）     * @param url 链接地址     */    public static String sendGetRequest(String url, HashMap&lt;String, String&gt; Header) throws IOException &#123;        Request.Builder builder = new Request.Builder()                .url(url)                .get();        for (int i = 0; i &lt; MapUtil.ergodicHashMaps(Header).size(); i++) &#123;            builder.addHeader(MapUtil.ergodicHashMaps(Header).get(i).get(0).toString(), MapUtil.ergodicHashMaps(Header).get(i).get(1).toString());        &#125;        Response response = client.newCall(builder.build()).execute();        String a = Objects.requireNonNull(response.body()).string();        response.close();        return a;    &#125;    /**     * 上传资源图片     *     * @param path 文件路径     * @param url 上传链接     * @param Authorization Authorization     */    public static String uploadFile(String Authorization, String path, String url) throws IOException &#123;        File File = new File(path);        OkHttpClient client = new OkHttpClient().newBuilder()                .build();        RequestBody body = new MultipartBody.Builder().setType(MultipartBody.FORM)                .addFormDataPart(&quot;file&quot;, File.getName(),                        RequestBody.create(MediaType.parse(&quot;application/octet-stream&quot;),                                new File(path)))                .build();        Request request = new Request.Builder()                .url(url)                .addHeader(&quot;Authorization&quot;, Authorization)                .addHeader(&quot;Content-Type&quot;, &quot;multipart/form-data&quot;)                .method(&quot;POST&quot;, body)                .build();        try (Response response = client.newCall(request).execute()) &#123;            return Objects.requireNonNull(response.body()).string();        &#125;    &#125;    /**     * 模拟浏览器发送请求     * @param url 链接地址     */    public static String simulationBrowserRequest(String url) throws IOException &#123;        HashMap&lt;String, String&gt; Header = new HashMap&lt;&gt;();        Header.put(&quot;User-Agent&quot;, &quot;Mozilla/5.0 (Windows NT 6.1; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/68.0.3440.106 Safari/537.36&quot;);        return sendGetRequest(url, Header);    &#125;    /**     * 发送普通的Get请求     * @param url 链接地址     */    public static String sendGetRequest(String url) throws IOException &#123;        return sendGetRequest(url, new HashMap&lt;&gt;());    &#125;    /**     * 从网络Url中下载文件     *     * @param url   路径     * @param saveDir  保存路径     * @param fileName 文件名称     * @throws IOException IOException异常     */    public static void downloadFile(String url, File saveDir, String fileName) throws IOException &#123;        Request request = new Request.Builder()                .url(url)                .get()                .addHeader(&quot;User-Agent&quot;, &quot;Mozilla/5.0 (Windows NT 6.1; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/68.0.3440.106 Safari/537.36&quot;)                .build();        Response response = client.newCall(request).execute();        byte[] bytes = Objects.requireNonNull(response.body()).bytes();        if (saveDir.exists()) &#123;            saveDir.mkdirs();        &#125;        String folder = saveDir + File.separator + fileName;        File file = new File(folder);        FileOutputStream fos = new FileOutputStream(file);        fos.write(bytes);        fos.close();    &#125;    /**     * 从网络Url中下载文件（使用文件原本名字）     *     * @param url   路径     * @param saveDir  保存路径     * @throws IOException IOException异常     */    public static void downloadFile(String url, File saveDir) throws IOException &#123;        Request request = new Request.Builder()                .url(url)                .get()                .addHeader(&quot;User-Agent&quot;, &quot;Mozilla/5.0 (Windows NT 6.1; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/68.0.3440.106 Safari/537.36&quot;)                .build();        Response response = client.newCall(request).execute();        byte[] bytes = Objects.requireNonNull(response.body()).bytes();        if (saveDir.exists()) &#123;            saveDir.mkdirs();        &#125;        String folder = saveDir + File.separator + StringUtils.substringAfterLast(url, &quot;/&quot;);        File file = new File(folder);        FileOutputStream fos = new FileOutputStream(file);        fos.write(bytes);        fos.close();    &#125;&#125;
